import React from 'react';
import {Link} from 'react-scroll'
import GitHubIcon from '@material-ui/icons/GitHub';
import LinkedInIcon from '@material-ui/icons/LinkedIn';
import IconButton from '@material-ui/core/IconButton';
import { AppBar, Toolbar, Button, Grid } from "@material-ui/core";
import { spacing } from '@material-ui/system';


class Header extends React.Component {
      render() {
        return(
            <AppBar position="sticky" >
                  <Toolbar variant="dense">
                    <Grid container alignItems="center" direction="row" justify="space-between">
                      <div>
                        <IconButton aria-label="Linkedin.com" onClick={() => window.open('https://www.linkedin.com/in/richard-woessner/')}>
                          <LinkedInIcon color="action"/>
                        </IconButton>

                        <IconButton aria-label="GitHub.com" onClick={() => window.open('https://github.com/Richard-Woessner')}>
                          <GitHubIcon color="action"/>
                        </IconButton>
                      </div>
                        <h3>Richard Woessner III</h3>
                      <div>

                      </div>

                      <div>
                        <Link to="interests"><Button color="inherit">About-Me</Button></Link>
                        <Button color="inherit">My-Work</Button>
                        <Button color="inherit">Interests</Button>
                        <Button color="inherit">Contact-Me</Button>
                      </div>
                    </Grid>
                  </Toolbar>
            </AppBar>
        );
      }
    }

export default Header;
